package com.parkflow.mall.payment.controller;
import com.parkflow.mall.payment.dto.PaymentDtos.*; import com.parkflow.mall.payment.service.PaymentService; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/payments") public class PaymentController { private final PaymentService service; public PaymentController(PaymentService s){service=s;} @PostMapping("/orders") public OrderResponse create(@RequestBody CreateOrderRequest r,@RequestHeader(value="Idempotency-Key",required=false) String key){return service.create(r,key);}@GetMapping("/orders/{id}") public OrderResponse get(@PathVariable String id){return service.get(id);}@PostMapping("/simulations/success") public SimulationResponse simulate(@RequestBody SimulateRequest r,@RequestHeader(value="Idempotency-Key",required=false) String key){return service.simulate(r,key);} }
